import{_ as e,c as l,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Agent Skills 入门: 扩展 AI 编码代理能力 | Agent Skills","description":"学习 Agent Skills 的核心功能和使用方法。了解如何扩展 Claude、Cursor 等 AI 编码代理能力，掌握 React 性能优化、Web 设计指南和一键部署三大技能包。","frontmatter":{"title":"Agent Skills 入门: 扩展 AI 编码代理能力 | Agent Skills","sidebarTitle":"扩展 AI 能力","subtitle":"Agent Skills 入门: 扩展 AI 编码代理能力","description":"学习 Agent Skills 的核心功能和使用方法。了解如何扩展 Claude、Cursor 等 AI 编码代理能力，掌握 React 性能优化、Web 设计指南和一键部署三大技能包。","tags":["入门","AI 编码代理","Claude","技能包"],"order":10,"prerequisite":[]},"headers":[],"relativePath":"zh/vercel-labs/agent-skills/start/getting-started/index.md","filePath":"zh/vercel-labs/agent-skills/start/getting-started/index.md"}'),s={name:"zh/vercel-labs/agent-skills/start/getting-started/index.md"};function r(o,t,d,n,c,h){return i(),l("div",null,[...t[0]||(t[0]=[a(`<h1 id="agent-skills-入门" tabindex="-1">Agent Skills 入门 <a class="header-anchor" href="#agent-skills-入门" aria-label="Permalink to &quot;Agent Skills 入门&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解 Agent Skills 是什么，以及它如何扩展 AI 编码代理的能力</li><li>了解三大核心技能包的功能和使用场景</li><li>知道什么时候适合使用 Agent Skills 来提升开发效率</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你日常使用 Claude、Cursor 或其他 AI 编码代理时，可能会遇到这些问题：</p><ul><li>希望遵循最佳实践，但不知道该记住哪些规则</li><li>经常重复类似的部署操作，希望自动化</li><li>AI 生成的代码质量参差不齐，缺少统一标准</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Agent Skills 是技能包系统</strong>——为 AI 编码代理提供可扩展的「插件」。每个技能包含：</p><ul><li><strong>SKILL.md</strong>：技能定义文件，告诉 AI 代理什么时候激活该技能</li><li><strong>scripts/</strong>：辅助脚本（如部署脚本），执行具体任务</li><li><strong>references/</strong>：辅助文档（可选），提供详细参考资料</li></ul><div class="tip custom-block"><p class="custom-block-title">设计理念</p><p>技能采用<strong>按需加载</strong>机制：只有技能名称和描述在启动时加载，完整内容在 AI 判断需要时才读取。这样可以减少上下文占用，提高效率。</p></div><h2 id="可用的技能包" tabindex="-1">可用的技能包 <a class="header-anchor" href="#可用的技能包" aria-label="Permalink to &quot;可用的技能包&quot;">​</a></h2><p>项目提供三大技能包，每个都针对特定场景：</p><h3 id="react-best-practices" tabindex="-1">react-best-practices <a class="header-anchor" href="#react-best-practices" aria-label="Permalink to &quot;react-best-practices&quot;">​</a></h3><p>React 和 Next.js 性能优化指南，来自 Vercel Engineering 标准。包含 50+ 条规则，按影响级别排序。</p><p><strong>使用场景</strong>：</p><ul><li>编写新的 React 组件或 Next.js 页面</li><li>审查代码性能问题</li><li>优化包大小或加载时间</li></ul><p><strong>覆盖类别</strong>：</p><ul><li>消除瀑布（Critical）</li><li>包大小优化（Critical）</li><li>服务端性能（High）</li><li>客户端数据获取（Medium-High）</li><li>Re-render 优化（Medium）</li><li>渲染性能（Medium）</li><li>JavaScript 微优化（Low-Medium）</li><li>高级模式（Low）</li></ul><h3 id="web-design-guidelines" tabindex="-1">web-design-guidelines <a class="header-anchor" href="#web-design-guidelines" aria-label="Permalink to &quot;web-design-guidelines&quot;">​</a></h3><p>Web 界面设计指南审计，检查代码是否符合近百条最佳实践。</p><p><strong>使用场景</strong>：</p><ul><li>提示词：&quot;Review my UI&quot;</li><li>检查可访问性（Accessibility）</li><li>审计设计一致性</li><li>检查性能和 UX</li></ul><p><strong>覆盖类别</strong>：</p><ul><li>可访问性（aria-labels、语义化 HTML、键盘处理）</li><li>Focus 状态（可见焦点、focus-visible 模式）</li><li>表单（自动完成、验证、错误处理）</li><li>动画（prefers-reduced-motion、合成友好的变换）</li><li>图片（尺寸、懒加载、alt 文本）</li><li>排版、性能、导航等</li></ul><h3 id="vercel-deploy-claimable" tabindex="-1">vercel-deploy-claimable <a class="header-anchor" href="#vercel-deploy-claimable" aria-label="Permalink to &quot;vercel-deploy-claimable&quot;">​</a></h3><p>一键部署应用和网站到 Vercel，返回预览链接和所有权转移链接。</p><p><strong>使用场景</strong>：</p><ul><li>提示词：&quot;Deploy my app&quot;</li><li>快速分享项目预览</li><li>无需配置，零认证部署</li></ul><p><strong>核心特性</strong>：</p><ul><li>自动检测 40+ 种框架（Next.js、Vite、Astro 等）</li><li>返回预览 URL（实时站点）和 claim URL（转移所有权）</li><li>自动处理静态 HTML 项目</li><li>上传时排除 <code>node_modules</code> 和 <code>.git</code></li></ul><h2 id="技能的工作原理" tabindex="-1">技能的工作原理 <a class="header-anchor" href="#技能的工作原理" aria-label="Permalink to &quot;技能的工作原理&quot;">​</a></h2><p>当你使用 Claude 或其他 AI 代理时，技能激活流程如下：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[用户输入任务] --&gt; B[AI 检测关键词&lt;br/&gt;如 Deploy, Review, Optimize]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[匹配技能描述]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[加载 SKILL.md 完整内容]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[执行脚本或应用规则]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[输出结果给用户]</span></span></code></pre></div><p><strong>示例流程</strong>：</p><ol><li><strong>用户输入</strong>：&quot;Deploy my app&quot;</li><li><strong>AI 检测</strong>：识别关键词 &quot;Deploy&quot;，匹配 <code>vercel-deploy</code> 技能</li><li><strong>加载技能</strong>：读取 <code>SKILL.md</code> 完整内容</li><li><strong>执行部署</strong>： <ul><li>运行 <code>deploy.sh</code> 脚本</li><li>检测框架（读取 package.json）</li><li>打包项目为 tarball</li><li>上传到 Vercel API</li></ul></li><li><strong>返回结果</strong>：<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>使用 Agent Skills 的最佳时机：</p><table tabindex="0"><thead><tr><th>场景</th><th>使用的技能</th><th>触发提示词示例</th></tr></thead><tbody><tr><td>编写 React 组件</td><td>react-best-practices</td><td>&quot;Review this React component for performance issues&quot;</td></tr><tr><td>优化 Next.js 页面</td><td>react-best-practices</td><td>&quot;Help me optimize this Next.js page&quot;</td></tr><tr><td>检查 UI 质量</td><td>web-design-guidelines</td><td>&quot;Check accessibility of my site&quot;</td></tr><tr><td>部署项目</td><td>vercel-deploy-claimable</td><td>&quot;Deploy my app to production&quot;</td></tr></tbody></table><h2 id="安全模型" tabindex="-1">安全模型 <a class="header-anchor" href="#安全模型" aria-label="Permalink to &quot;安全模型&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">安全说明</p><ul><li><strong>本地运行</strong>：所有技能在本地执行，无数据上传至第三方服务（Vercel 部署 API 除外）</li><li><strong>按需激活</strong>：技能仅在 AI 判断相关时加载详细内容，减少隐私泄露风险</li><li><strong>开源透明</strong>：所有技能和脚本开源可审计</li></ul></div><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="技能未激活" tabindex="-1">技能未激活 <a class="header-anchor" href="#技能未激活" aria-label="Permalink to &quot;技能未激活&quot;">​</a></h3><p>如果技能没有被激活，检查：</p><ul><li>提示词是否包含足够的关键词（如 &quot;Deploy&quot;、&quot;Review&quot;）</li><li>技能是否正确安装到 <code>~/.claude/skills/</code> 目录</li><li>如果使用 claude.ai，确认技能已添加到项目知识库</li></ul><h3 id="网络权限" tabindex="-1">网络权限 <a class="header-anchor" href="#网络权限" aria-label="Permalink to &quot;网络权限&quot;">​</a></h3><p>某些技能需要网络访问：</p><ul><li><code>vercel-deploy-claimable</code> 需要访问 Vercel 部署 API</li><li><code>web-design-guidelines</code> 需要从 GitHub 拉取最新规则</li></ul><p><strong>解决方案</strong>：在 claude.ai/settings/capabilities 中添加所需域名。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Agent Skills 是为 AI 编码代理设计的技能包系统，提供：</p><ul><li><strong>react-best-practices</strong>：50+ 条 React/Next.js 性能优化规则</li><li><strong>web-design-guidelines</strong>：近百条 Web 设计最佳实践</li><li><strong>vercel-deploy-claimable</strong>：一键部署到 Vercel</li></ul><p>技能采用按需加载机制，减少上下文占用。安装后，AI 代理会自动在相关任务中激活对应的技能。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们将学习 <strong><a href="./../installation/">安装 Agent Skills</a></strong>。</p><p>你将学到：</p><ul><li>两种安装方法：Claude Code 和 claude.ai</li><li>配置网络权限</li><li>验证技能是否正确安装</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>技能包列表</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L7-L80" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>7-80</td></tr><tr><td>技能结构说明</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L103-L110" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>103-110</td></tr><tr><td>AGENTS.md 规范</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>全文</td></tr><tr><td>技能目录结构</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>11-20</td></tr><tr><td>SKILL.md 格式</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>29-68</td></tr><tr><td>技能打包命令</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L93-L96" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>93-96</td></tr><tr><td>用户安装方法</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L110" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>98-110</td></tr><tr><td>按需加载机制</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L72-L78" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>72-78</td></tr><tr><td>构建工具脚本</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>全文</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li>无硬编码常量</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>build.ts</code>：构建 AGENTS.md 和测试用例</li><li><code>validate.ts</code>：验证规则文件完整性</li><li><code>extract-tests.ts</code>：从规则中提取测试用例</li></ul></details>`,57)])])}const u=e(s,[["render",r]]);export{g as __pageData,u as default};
